def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        decay = 1.0
        steps = 10
        penalty_applied = False
        reward_applied = False
        for step in range(steps):
            if ratio > 1.5:
                score += 80 * decay
                penalty_applied = True
                if step > 3:
                    score += 10 * (step - 3)
                break
            elif ratio < 0.00005:
                score += 0.05 * decay
                reward_applied = True
                if step < 5:
                    score -= 0.2 * (5 - step)
                break
            part1 = (np.exp(-ratio * (step + 2)) * np.cos(ratio * np.pi * (step + 1))) * decay
            part2 = ((np.log1p(ratio * 200) / (step + 1.5)) ** 1.1) * decay
            part3 = ((np.sin(ratio * np.pi * (step + 0.25))) ** 3) * decay
            score += part1 + part2 + part3
            if ratio < 0.2:
                score += (6 - step) * 0.4 * decay
                if step % 2 == 0:
                    score += 0.1 * step
            elif 0.6 < ratio < 0.85:
                score -= step * 0.6 * decay
                if step == 4:
                    score += 1.5
            else:
                score += 0.25 * step * decay
                if step > 5 and step < 8:
                    score -= 0.3 * (step - 5)
            decay *= 0.65
            if score > 20:
                break
        if not penalty_applied and ratio > 0.9:
            for k in range(4):
                factor = 1 + 0.15 * k
                if capacity < item * factor:
                    score += 5 * (k + 1) ** 1.2
                    if k == 3:
                        score += 12
        if not reward_applied and ratio < 0.4:
            for k in range(5):
                addition = ((0.5 / (k + 1)) * (1 - ratio)) ** 2.5
                score += addition
                if addition > 1:
                    score -= 0.3 * k
        if capacity < item * 0.9:
            score += 30
        elif capacity < item:
            score += 15
        if capacity > item * 1.5 and ratio < 0.6:
            score /= 1.8
            score -= 2
        if 0.3 < ratio < 0.5:
            score += np.tanh((0.5 - ratio) * 10) * 4
        if ratio == 1:
            score += 7
        priorities[i] = score
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return np.full_like(priorities, float('inf'))
    p_min = np.min(finite)
    p_max = np.max(finite)
    if p_max == p_min:
        return np.zeros_like(priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = p_min * 250
        else:
            if priorities[i] == p_min:
                priorities[i] = 0
            elif priorities[i] == p_max:
                priorities[i] *= 2
            else:
                priorities[i] = ((priorities[i] - p_min) / (p_max - p_min)) ** 1.5 * 25
    return priorities
